{
  "shots": [
    {
      "shot_id": "SH12",
      "priority": "P1",
      "intent": "完成美咲与樱子从站台进入新干线车厢并在相邻座席坐下的空间转换，为下一镜列车启动做铺垫。",
      "duration_sec": 5,
      "shot_type": "双人中景",
      "movement": "极轻微稳定跟拍",
      "framing_focus": "首帧定格在新干线车厢入口的竖屏双人中景，1扇新干线车门位于画面中心，佐藤美咲和佐藤樱子站在门旁相牵等待登车，两人三分之二侧脸和眼神清楚可见。",
      "action_intent": "本镜头只执行登车落座的过渡任务：1扇新干线车门滑开一次，美咲牵着樱子进入车厢，短步走到靠窗的2个相邻座席并坐下，樱子坐在美咲旁边微微靠近。",
      "emotion_intent": "从离站前的不舍转为相互信任，落座后形成安定的新生空间。",
      "scene_id": "EP21_SHINKANSEN_WINDOW_SEAT",
      "scene_name": "新干线车厢靠窗座位",
      "dialogue": [],
      "narration": [],
      "subtitle": [],
      "positive_core": "首帧定格在新干线车厢入口的竖屏双人中景，1扇米白色车体边框的新干线车门闭合在画面中心，佐藤美咲位于画面右侧三分之二侧脸可见，佐藤樱子位于画面左侧三分之二侧脸可见，两人站在门旁相牵等待登车。美咲穿低饱和浅米色旧丝质过膝礼服，细肩带略松但衣着完整，黑色低跟鞋，头发自然垂落；樱子穿深蓝色中学生水手服套装，白色领巾，及膝百褶裙，白色袜子，黑色学生皮鞋，朴素日常呈现。随后车门伴随拉长的金属摩擦声单侧滑开一次，美咲轻轻牵着樱子迈入车厢，镜头极轻微稳定跟随到靠窗座位区；2个低饱和蓝灰色布面相邻座席进入画面中心，两人坐下，座椅布面产生轻微压陷，樱子安静靠近美咲。清晨车厢光线低饱和，金属门框、蓝灰织物座椅和窗边冷光保持写实电影感，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "first_frame_contract": {
        "location": "新干线车厢入口",
        "visual_center": "画面中心的1扇新干线车门与门旁相牵等待登车的佐藤美咲、佐藤樱子",
        "visible_characters": [
          "佐藤美咲",
          "佐藤樱子"
        ],
        "character_positions": {
          "佐藤美咲": "画面右侧，靠近车门边框，身体朝向车门，脸部呈三分之二侧脸",
          "佐藤樱子": "画面左侧，站在美咲身旁，右手与美咲相牵，脸部呈三分之二侧脸"
        },
        "character_face_visibility": {
          "佐藤美咲": "脸部可见，三分之二侧脸；可见五官和眼神，目光朝向即将开启的车门与车内座席方向",
          "佐藤樱子": "脸部可见，三分之二侧脸；可见五官和眼神，目光跟随美咲"
        },
        "key_props": [
          "SHINKANSEN_TRAIN_DOOR",
          "TRAIN_SEAT_PAIR"
        ],
        "speaking_state": "佐藤美咲和佐藤樱子均保持沉默，只有车站提示音、车门金属滑动声与车厢环境声",
        "camera_motion_allowed": "首帧稳定，车门开启后允许极轻微稳定跟拍至座位区"
      },
      "dialogue_blocking": {
        "active_speaker": "none",
        "first_speaker": "none",
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [
          "佐藤美咲",
          "佐藤樱子"
        ],
        "lip_sync_policy": "no_dialogue"
      },
      "i2v_contract": {
        "shot_task": "transition",
        "risk_level": "medium",
        "risk_notes": "5秒内包含车门开启、进入车厢、相邻落座的连续空间转换；通过短距离走位、稳定跟拍和固定道具位置控制，镜头只承担登车落座任务。",
        "prop_library": {
          "SHINKANSEN_TRAIN_DOOR": {
            "display_name": "新干线车门",
            "count": "1扇主车门",
            "size": "宽约0.9米，高约2.0米",
            "color": "米白色车体边框，银灰色金属门边，深色玻璃窗",
            "material": "涂装金属、橡胶密封条、钢化玻璃",
            "structure": "单侧滑动车门，门上有竖向窄窗",
            "front_description": null,
            "back_description": null,
            "canonical_motion_policy": "在SH12滑开一次，保持打开直到两人进入"
          },
          "TRAIN_SEAT_PAIR": {
            "display_name": "新干线相邻座席",
            "count": "2个相邻座席",
            "size": "每个座席宽约0.48米，高约1.15米，座深约0.45米",
            "color": "低饱和蓝灰色布面，黑色扶手",
            "material": "织物座椅、塑料扶手、金属支架",
            "structure": "并排双座，靠背竖直，座椅面略向后倾",
            "front_description": null,
            "back_description": null,
            "canonical_motion_policy": "固定在车厢地板，人物坐下时仅产生轻微坐垫压陷"
          }
        },
        "prop_contract": [
          {
            "prop_id": "SHINKANSEN_TRAIN_DOOR",
            "position": "本镜头首帧位于画面中心的新干线车厢入口",
            "first_frame_visible": true,
            "motion_policy": "从闭合状态单侧滑开一次，人物进入后保持打开状态至镜头结束",
            "controlled_by": "none",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "本镜头仅呈现1扇主车门作为车门主体",
            "flip_policy": "none"
          },
          {
            "prop_id": "TRAIN_SEAT_PAIR",
            "position": "车厢内靠窗座位区，首帧位于车门后方纵深处，人物进入后成为画面中心",
            "first_frame_visible": false,
            "motion_policy": "固定在车厢地板，两人坐下时仅产生轻微坐垫压陷，随后保持静止",
            "controlled_by": "none",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "本镜头仅呈现2个相邻座席作为落座主体",
            "flip_policy": "none"
          }
        ],
        "phone_contract": null
      },
      "source_basis": "“列车门开启，金属的摩擦声拉长，两人踏入车厢。座席的布料凉意贴近肌肤，美咲坐下，樱子靠在旁。”对应事实切片12：新干线车门打开，美咲和樱子进入车厢并坐在相邻座位上。"
    }
  ],
  "qa_report": [
    {
      "check": "shots array length and shot id",
      "result": "pass",
      "notes": "仅生成1个镜头，shot_id为SH12，duration_sec为5。"
    },
    {
      "check": "TARGET_FACTS and TARGET_SPINE_ROW traceability",
      "result": "pass",
      "notes": "镜头内容严格对应事实切片12与SH12任务：车门滑开、两人进入车厢、坐在相邻座席。"
    },
    {
      "check": "I2V one-shot one-task",
      "result": "pass",
      "notes": "shot_task为transition，镜头只完成登车落座的空间转换。"
    },
    {
      "check": "dialogue and lip sync",
      "result": "pass",
      "notes": "本镜头无对白，佐藤美咲和佐藤樱子均保持沉默，无电话声音。"
    },
    {
      "check": "first frame face visibility",
      "result": "pass",
      "notes": "首帧两名可见角色均为三分之二侧脸，可见五官和眼神。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "使用并定义SHINKANSEN_TRAIN_DOOR与TRAIN_SEAT_PAIR，数量、尺寸、颜色、材质、结构和运动策略均沿用道具目录。"
    },
    {
      "check": "costume continuity",
      "result": "pass",
      "notes": "佐藤美咲与佐藤樱子的服装沿用本集服装契约，未新增换装事件。"
    },
    {
      "check": "continuity from SH11",
      "result": "pass",
      "notes": "SH11已完成石川离开，本镜头转入新干线登车流程，未重复石川退出信息。"
    }
  ]
}
